use actix_web_actors::ws;

struct WsSession;

impl actix::Actor for WsSession {
    type Context = ws::WebsocketContext<Self>;
}

impl ws::StreamHandler<Result<ws::Message, ws::ProtocolError>> for WsSession {
    fn handle(&mut self, msg: Result<ws::Message, ws::ProtocolError>, ctx: &mut Self::Context) {
        match msg {
            Ok(ws::Message::Text(text)) => ctx.text(format!("echo: {text}")),
            Ok(ws::Message::Ping(msg)) => ctx.pong(&msg),
            Ok(ws::Message::Close(reason)) => { ctx.close(reason); ctx.stop(); }
            _ => {}
        }
    }
}

Code Bad:
async fn ws_handler(req: HttpRequest, payload: web::Payload) -> impl Responder {
    // no heartbeat, no timeout, connection lives forever
    ws::start(WsSession, &req, payload)
}

